1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  items: Item[];
9	}
10	
11	interface Customer {
12	  yearsWithMHPCO: number;
13	}
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	
23	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	};
29	
30	const COMPONENT_TYPES = ["rune", "moonstone"];
31	const COMPONENT_PREMIUM = 25;
32	const BLOCK_SIZE = 3;
33	const BLOCK_PREMIUM = 60;
34	
35	// Sum `valueOf` applied to each element of an iterable.
36	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
37	  let sum = 0;
38	  for (const value of values) sum += valueOf(value);
39	  return sum;
40	};
41	
42	const isComponent = (item: Item): boolean =>
43	  COMPONENT_TYPES.includes(item.type);
44	
45	const isMainItem = (item: Item): boolean => !isComponent(item);
46	
47	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
48	// BLOCK_PREMIUM; any other count is priced per component.
49	const componentGroupBasePremium = (count: number): number =>
50	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
51	
52	// An item-specific surcharge adds `rate` of the item's base premium when its
53	// condition holds, and nothing otherwise.
54	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
55	  applies ? rate * basePremiumForItem(item) : 0;
56	
57	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
58	const curseSurcharge = (item: Item): number =>
59	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
60	
61	// Highly enchanted items (enchantment at or above the threshold) add a
62	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
63	const highEnchantmentSurcharge = (item: Item): number =>
64	  surchargeWhen(
65	    item,
66	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
67	    HIGH_ENCHANTMENT_SURCHARGE,
68	  );
69	
70	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
71	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
72	// that is only spuriously above a whole number.
73	const roundUpInMHPCOsFavor = (amount: number): number =>
74	  Math.ceil(Number(amount.toFixed(6)));
75	
76	const basePremiumForItem = (item: Item): number =>
77	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
78	
79	// Each main item is priced on its own.
80	const mainItemsBasePremium = (items: Item[]): number =>
81	  sumOf(items, basePremiumForItem);
82	
83	const countByType = (items: Item[]): Map<string, number> => {
84	  const counts = new Map<string, number>();
85	  for (const item of items) {
86	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
87	  }
88	  return counts;
89	};
90	
91	// Components are grouped by type, and each group is block-priced.
92	const componentsBasePremium = (components: Item[]): number =>
93	  sumOf(countByType(components).values(), componentGroupBasePremium);
94	
95	const policyBasePremium = (items: Item[]): number =>
96	  mainItemsBasePremium(items.filter(isMainItem)) +
97	  componentsBasePremium(items.filter(isComponent));
98	
99	// Tier 1 — item-specific surcharges: computed off each affected item's base
100	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
101	const itemSurcharges = (items: Item[]): number =>
102	  sumOf(items, (item) => curseSurcharge(item) + highEnchantmentSurcharge(item));
103	
104	// Long-standing customers (at or above the loyalty threshold) receive a
105	// discount equal to LOYALTY_DISCOUNT of the policy base premium.
106	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
107	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
108	    ? LOYALTY_DISCOUNT * policyBase
109	    : 0;
110	
111	// Tier 2 — policy-wide modifiers: computed as a fraction of the policy base
112	// premium. (e.g. first-insurance surcharge; later loyalty/follow-up discounts.)
113	const policyWideModifiers = (policyBase: number, customer: Customer): number =>
114	  FIRST_INSURANCE_SURCHARGE * policyBase - loyaltyDiscount(policyBase, customer);
115	
116	export const quote = (
117	  customer: Customer,
118	  step: QuoteStep,
119	  quoteIndex: number,
120	): number => {
121	  const policyBase = policyBasePremium(step.items);
122	
123	  const total =
124	    policyBase +
125	    itemSurcharges(step.items) +
126	    policyWideModifiers(policyBase, customer) +
127	    PROCESSING_FEE;
128	  return roundUpInMHPCOsFavor(total);
129	};
130	
131	export const claim = (...args: unknown[]): unknown => {
132	  return undefined; // Intentionally not implemented
133	};
